import"./modulepreload-polyfill-B5Qt9EMX.js";/* empty css              */document.addEventListener("DOMContentLoaded",()=>{const s=document.getElementById("screening-form"),o=document.getElementById("btn-submit"),m=document.getElementById("height"),u=document.getElementById("weight"),g=document.getElementById("bmi-result"),n=document.getElementById("bmi-category"),d=document.getElementById("bmi-hidden");function c(){const l=parseFloat(m.value),i=parseFloat(u.value);if(l>0&&i>0){const t=i/(l/100)**2,e=parseFloat(t.toFixed(2));g.textContent=e,d.value=e,t<18.5?(n.textContent="Kurus (Underweight)",n.className="px-3 py-1 rounded-full text-xs font-medium bg-blue-100 text-blue-700"):t<25?(n.textContent="Normal",n.className="px-3 py-1 rounded-full text-xs font-medium bg-green-100 text-green-700"):t<30?(n.textContent="Kelebihan Berat (Overweight)",n.className="px-3 py-1 rounded-full text-xs font-medium bg-yellow-100 text-yellow-700"):(n.textContent="Obesitas",n.className="px-3 py-1 rounded-full text-xs font-medium bg-red-100 text-red-700")}else g.textContent="0.0",d.value="",n.textContent="Belum dihitung",n.className="px-3 py-1 rounded-full text-xs font-medium bg-gray-200 text-gray-700"}m.addEventListener("input",c),u.addEventListener("input",c),s.addEventListener("submit",async l=>{if(l.preventDefault(),!s.checkValidity()){s.reportValidity();return}const i=parseFloat(d.value);if(!i||i<=0){Swal.fire({icon:"warning",title:"BMI belum dihitung",text:"Mohon isi Tinggi dan Berat Badan untuk menghitung BMI.",confirmButtonColor:"#0d9488"});return}const t=new FormData(s),e={nama:t.get("nama")||"Pasien",gender:t.get("gender"),age:parseFloat(t.get("age")),hypertension:parseInt(t.get("hypertension")),heart_disease:parseInt(t.get("heart_disease")),smoking_history:t.get("smoking_history"),bmi:i,HbA1c_level:parseFloat(t.get("HbA1c_level")),blood_glucose_level:parseFloat(t.get("blood_glucose_level"))};if(isNaN(e.age)||isNaN(e.bmi)||isNaN(e.HbA1c_level)||isNaN(e.blood_glucose_level)){Swal.fire({icon:"error",title:"Data tidak lengkap",text:"Pastikan semua field diisi dengan benar.",confirmButtonColor:"#0d9488"});return}const p=o.innerHTML;o.innerHTML='<i class="ph ph-spinner animate-spin"></i> Menganalisis...',o.disabled=!0;try{const a=await fetch("/api/predict",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(e)});if(!a.ok)throw new Error(`Server error: ${a.status}`);const r=await a.json();if(!r.success)throw new Error(r.message||"Prediksi gagal");localStorage.setItem("screeningResult",JSON.stringify({name:e.nama,gender:e.gender,age:e.age,bmi:e.bmi,HbA1c_level:e.HbA1c_level,blood_glucose_level:e.blood_glucose_level,hypertension:e.hypertension,heart_disease:e.heart_disease,smoking_history:e.smoking_history,prediction:r.prediction,probability:r.probability,risk_level:r.risk_level,date:new Date().toLocaleDateString("id-ID",{year:"numeric",month:"long",day:"numeric"})})),Swal.fire({icon:"success",title:"Analisis Selesai!",text:"Mengalihkan ke halaman hasil...",showConfirmButton:!1,timer:1800,timerProgressBar:!0}).then(()=>{window.location.href="/result.html"})}catch(a){console.error("Error:",a),Swal.fire({icon:"error",title:"Gagal Terhubung",html:`<p>Terjadi kesalahan saat menghubungi server.</p><p class="text-xs text-slate-400 mt-2">${a.message}</p>`,confirmButtonColor:"#0d9488"})}finally{o.innerHTML=p,o.disabled=!1}})});
